    #[allow(type_alias_bounds)]
    pub type BitmapComponentOf<E: ElectoralSystemRunner> =
        <<E as ElectoralSystemRunner>::Vote as VoteStorage>::BitmapComponent;
    #[allow(type_alias_bounds)]
